+
+		final List<ReporterSetup> reporterSetups = ReporterSetup.fromConfiguration(config);
+
+		Assert.assertEquals(1, reporterSetups.size());
+
+		final ReporterSetup setup = reporterSetups.get(0);
+		assertReporter2Configured(setup);
+	}
